import os
from cryptography.hazmat.primitives.ciphers.aead import AESGCM
from cryptography.hazmat.primitives import hashes
from cryptography.hazmat.primitives.kdf.pbkdf2 import PBKDF2
import secrets
import base64
from typing import Tuple

class SecureCreditCardEncryption:
    def __init__(self):
        encryption_key = os.environ.get('ENCRYPTION_KEY')
        if not encryption_key:
            raise ValueError("ENCRYPTION_KEY environment variable must be set")
        
        key_salt = os.environ.get('KEY_SALT')
        if not key_salt:
            raise ValueError("KEY_SALT environment variable must be set")
        
        kdf = PBKDF2(
            algorithm=hashes.SHA256(),
            length=32,
            salt=base64.b64decode(key_salt),
            iterations=100000,
        )
        self.key = kdf.derive(encryption_key.encode())
        self.aesgcm = AESGCM(self.key)
    
    def encrypt_credit_card(self, card_number: str) -> str:
        if not card_number or not isinstance(card_number, str):
            raise ValueError("Invalid credit card number")
        
        card_digits = ''.join(filter(str.isdigit, card_number))
        if len(card_digits) < 13 or len(card_digits) > 19:
            raise ValueError("Credit card number must be between 13 and 19 digits")
        
        nonce = secrets.token_bytes(12)
        
        plaintext = card_number.encode('utf-8')
        ciphertext = self.aesgcm.encrypt(nonce, plaintext, None)
        
        encrypted_data = nonce + ciphertext
        return base64.b64encode(encrypted_data).decode('utf-8')
    
    def decrypt_credit_card(self, encrypted_data: str) -> str:
        if not encrypted_data or not isinstance(encrypted_data, str):
            raise ValueError("Invalid encrypted data")
        
        try:
            encrypted_bytes = base64.b64decode(encrypted_data)
        except Exception:
            raise ValueError("Invalid base64 encoded data")
        
        if len(encrypted_bytes) < 13:
            raise ValueError("Encrypted data is too short")
        
        nonce = encrypted_bytes[:12]
        ciphertext = encrypted_bytes[12:]
        
        plaintext = self.aesgcm.decrypt(nonce, ciphertext, None)
        return plaintext.decode('utf-8')
    
    def get_last_four_digits(self, card_number: str) -> str:
        card_digits = ''.join(filter(str.isdigit, card_number))
        return card_digits[-4:] if len(card_digits) >= 4 else ''


def encrypt_credit_card_for_storage(card_number: str) -> Tuple[str, str]:
    encryptor = SecureCreditCardEncryption()
    encrypted = encryptor.encrypt_credit_card(card_number)
    last_four = encryptor.get_last_four_digits(card_number)
    return encrypted, last_four


def decrypt_credit_card_from_storage(encrypted_data: str) -> str:
    encryptor = SecureCreditCardEncryption()
    return encryptor.decrypt_credit_card(encrypted_data)


def generate_encryption_key_and_salt():
    encryption_key = base64.b64encode(secrets.token_bytes(32)).decode('utf-8')
    key_salt = base64.b64encode(secrets.token_bytes(16)).decode('utf-8')
    
    print("Add these to your environment variables (e.g., .env file or secrets manager):")
    print(f"ENCRYPTION_KEY={encryption_key}")
    print(f"KEY_SALT={key_salt}")
    print("\nNEVER commit these values to version control!")
    print("Store them in a secure secrets management system (AWS Secrets Manager, HashiCorp Vault, etc.)")
    
    return encryption_key, key_salt


if __name__ == "__main__":
    if not os.environ.get('ENCRYPTION_KEY') or not os.environ.get('KEY_SALT'):
        print("Generating new encryption key and salt...")
